### Configure Lexical Editor with Custom Slate Converters in Payload CMS

Source: https://github.com/payloadcms/payload/blob/main/docs/rich-text/migration.mdx

Demonstrates how to register custom Slate-to-Lexical converters in a Payload collection configuration. The converters are added to the SlateToLexicalFeature alongside default converters, enabling the migration of custom node types during the conversion process.

```typescript
import type { CollectionConfig } from 'payload'
import { lexicalEditor } from '@payloadcms/richtext-lexical'
import {
  SlateToLexicalFeature,
  defaultSlateConverters,
} from '@payloadcms/richtext-lexical/migrate'
import { MyCustomConverter } from './converters/MyCustomConverter'

const Pages: CollectionConfig = {
  slug: 'pages',
  fields: [
    {
      name: 'content',
      type: 'richText',
      editor: lexicalEditor({
        features: ({ defaultFeatures }) => [
          ...defaultFeatures,
          SlateToLexicalFeature({
            converters: [...defaultSlateConverters, MyCustomConverter],
          }),
        ],
      }),
    },
  ],
}
```

